SELECT hours, total_cost
FROM workforce_data
WHERE date = '2010-01-01';

SELECT hours, total_cost
FROM workforce_data
WHERE year = 2010;

SELECT SUM(total_cost) AS total_project_cost
FROM workforce_data
WHERE project_id = 1;

SELECT SUM(total_cost) AS total_weekly_cost
FROM workforce_data
WHERE year = 1 AND week_in_year = 1;

SELECT SUM(total_cost) AS total_project_cost
FROM workforce_data
WHERE project_id = 1 AND year = 2010 AND week_in_year = 1;

SELECT SUM(total_cost) AS total_cost_2010
FROM workforce_data
WHERE year = 2010;

SELECT project_id, SUM(total_cost) AS total_project_cost
FROM workforce_data
GROUP BY project_id;

SELECT total_cost, project_id
FROM workforce_data
WHERE year = 2010 AND week_in_year = 1;
